mapper.update:
UPDATE notification
SET status = 1, read_at = IFNULL(read_at, NOW()), updated_at = NOW()
WHERE id = #{id} AND user_id = #{userId}

UPDATE notification
SET status = 2, archived_at = NOW(), updated_at = NOW()
WHERE id = #{id} AND user_id = #{userId}

mapper.select:
SELECT *
FROM notification
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY created_at DESC
